mapper.select:
select * from pf_course
coach_name like concat('%', #{coachName}, '%') and status = #{status}
order by course_date desc, start_time desc

mapper.update:
update pf_course
course_name = #{courseName}, coach_name = #{coachName}, course_date = #{courseDate}, start_time = #{startTime}, end_time = #{endTime}, max_capacity = #{maxCapacity}, location = #{location}, status = #{status}, update_time = now()
where id = #{id}
